#!/bin/sh
# iptables-init.sh — egress interception for Envoy sidecar
# Generated by the egress generator (allowlist-agnostic; CIDRs injected at runtime).
#
# Required env vars (inject via Kubernetes Downward API / deployment env):
#   POD_CIDR     — pod network CIDR (default: 10.244.0.0/16)
#   SERVICE_CIDR — service cluster CIDR (default: 10.96.0.0/12)
#   HOST_IP      — node IP (from status.hostIP via fieldRef)
#
set -e

POD_CIDR="${POD_CIDR:-10.244.0.0/16}"
SERVICE_CIDR="${SERVICE_CIDR:-10.96.0.0/12}"

# Create custom chain for egress redirection
iptables -t nat -N ENVOY_EGRESS 2>/dev/null || true

# Skip traffic from Envoy itself (UID 1337)
iptables -t nat -A ENVOY_EGRESS -m owner --uid-owner 1337 -j RETURN

# Skip loopback — includes HTTP_PROXY traffic going to 127.0.0.1:15000
iptables -t nat -A ENVOY_EGRESS -d 127.0.0.0/8 -j RETURN

# Skip link-local (AWS metadata, GCP metadata, etc.)
iptables -t nat -A ENVOY_EGRESS -d 169.254.0.0/16 -j RETURN

# Skip Envoy management ports
iptables -t nat -A ENVOY_EGRESS -p tcp --dport 15000 -j RETURN
iptables -t nat -A ENVOY_EGRESS -p tcp --dport 15001 -j RETURN
iptables -t nat -A ENVOY_EGRESS -p tcp --dport 9901  -j RETURN

# Skip pod CIDR (intra-cluster pod traffic is handled by NetworkPolicy, not Envoy)
iptables -t nat -A ENVOY_EGRESS -d "${POD_CIDR}" -j RETURN

# Skip service CIDR (kube-proxy handles service VIPs via its own nat rules)
iptables -t nat -A ENVOY_EGRESS -d "${SERVICE_CIDR}" -j RETURN

# Skip node IP (health checks, kubelet API, host-networked services)
if [ -n "${HOST_IP}" ]; then
  iptables -t nat -A ENVOY_EGRESS -d "${HOST_IP}/32" -j RETURN
fi

# Skip UDP DNS (CoreDNS must be reachable for runtime hostname resolution)
iptables -t nat -A ENVOY_EGRESS -p udp --dport 53 -j RETURN

# Redirect all remaining TCP egress to Envoy transparent proxy
iptables -t nat -A ENVOY_EGRESS -p tcp -j REDIRECT --to-ports 15001

# Apply chain to OUTPUT (covers all outbound traffic from this pod's net namespace)
iptables -t nat -A OUTPUT -p tcp -j ENVOY_EGRESS

echo "ENVOY_EGRESS iptables chain configured."
iptables -t nat -L ENVOY_EGRESS -n -v
